/**
 * Regression tests for the shared routing policy module.
 *
 * These tests guard against accidental drift between MODEL_CANDIDATES,
 * MODEL_FAMILIES, keyword arrays, and the classification helpers.  They have
 * no external dependencies — only Node's built-in test runner and assert.
 *
 * Run with:
 *   node --test tests/routing-policy.test.mjs
 */

import { strict as assert } from "node:assert";
import { describe, it } from "node:test";
import {
  MODEL_CANDIDATES,
  MODEL_FAMILIES,
  TOOL_KEYWORDS,
  ORCHESTRATION_KEYWORDS,
  EXPLICIT_REVIEW_KEYWORDS,
  getModelFamily,
  classifyPrompt,
  dedupeCandidates,
  getTierCandidates,
  orderCandidates,
  buildAdditionalContext,
  isSameModelFamily,
} from "../.github/lib/routing-policy.mjs";

// ---------------------------------------------------------------------------
// MODEL_CANDIDATES structure & tier consistency
// ---------------------------------------------------------------------------

describe("MODEL_CANDIDATES tiers", () => {
  it("has all three required tiers", () => {
    assert.ok(Array.isArray(MODEL_CANDIDATES.economy), "missing economy");
    assert.ok(Array.isArray(MODEL_CANDIDATES.builder), "missing builder");
    assert.ok(Array.isArray(MODEL_CANDIDATES.reasoning), "missing reasoning");
  });

  it("every entry has a non-empty id and a valid reasoningEffort", () => {
    const validEfforts = new Set([null, "low", "medium", "high"]);
    for (const [tier, models] of Object.entries(MODEL_CANDIDATES)) {
      for (const m of models) {
        assert.ok(typeof m.id === "string" && m.id.length > 0, `${tier}: missing id`);
        assert.ok(
          validEfforts.has(m.reasoningEffort),
          `${tier}/${m.id}: invalid reasoningEffort "${m.reasoningEffort}"`,
        );
      }
    }
  });

  it("economy tier models do not request high reasoning effort", () => {
    for (const m of MODEL_CANDIDATES.economy) {
      assert.notEqual(
        m.reasoningEffort,
        "high",
        `economy model ${m.id} should not use high reasoning effort`,
      );
    }
  });

  it("reasoning tier contains at least one model with high effort", () => {
    const hasHigh = MODEL_CANDIDATES.reasoning.some((m) => m.reasoningEffort === "high");
    assert.ok(hasHigh, "reasoning tier should have at least one high-effort model");
  });

  it("no duplicate id+effort combinations within a single tier", () => {
    for (const [tier, models] of Object.entries(MODEL_CANDIDATES)) {
      const seen = new Set();
      for (const m of models) {
        const key = `${m.id}:${m.reasoningEffort}`;
        assert.ok(!seen.has(key), `${tier}: duplicate entry ${key}`);
        seen.add(key);
      }
    }
  });
});

// ---------------------------------------------------------------------------
// MODEL_FAMILIES — must stay consistent with MODEL_CANDIDATES
// ---------------------------------------------------------------------------

describe("MODEL_FAMILIES consistency", () => {
  it("every MODEL_CANDIDATES id is covered by a family", () => {
    const allIds = new Set(
      Object.values(MODEL_CANDIDATES)
        .flat()
        .map((m) => m.id),
    );
    const familyIds = new Set([...MODEL_FAMILIES.claude, ...MODEL_FAMILIES.gpt]);
    for (const id of allIds) {
      assert.ok(familyIds.has(id), `${id} not found in MODEL_FAMILIES`);
    }
  });

  it("claude family contains only claude-prefixed models", () => {
    for (const id of MODEL_FAMILIES.claude) {
      assert.ok(id.startsWith("claude-"), `${id} in claude set but does not start with claude-`);
    }
  });

  it("gpt family contains only gpt-prefixed models", () => {
    for (const id of MODEL_FAMILIES.gpt) {
      assert.ok(id.startsWith("gpt-"), `${id} in gpt set but does not start with gpt-`);
    }
  });

  it("getModelFamily returns the correct family string", () => {
    for (const id of MODEL_FAMILIES.claude) {
      assert.equal(getModelFamily(id), "claude", `expected claude for ${id}`);
    }
    for (const id of MODEL_FAMILIES.gpt) {
      assert.equal(getModelFamily(id), "gpt", `expected gpt for ${id}`);
    }
  });

  it("getModelFamily returns null for unknown ids", () => {
    assert.equal(getModelFamily("unknown-model-xyz"), null);
    assert.equal(getModelFamily(null), null);
    assert.equal(getModelFamily(""), null);
  });
});

// ---------------------------------------------------------------------------
// Keyword array exports — guards against accidental emptying
// ---------------------------------------------------------------------------

describe("keyword array exports", () => {
  it("TOOL_KEYWORDS is a non-empty array of strings", () => {
    assert.ok(Array.isArray(TOOL_KEYWORDS) && TOOL_KEYWORDS.length > 0);
    for (const kw of TOOL_KEYWORDS) {
      assert.equal(typeof kw, "string");
    }
  });

  it("ORCHESTRATION_KEYWORDS is a non-empty array of strings", () => {
    assert.ok(Array.isArray(ORCHESTRATION_KEYWORDS) && ORCHESTRATION_KEYWORDS.length > 0);
  });

  it("EXPLICIT_REVIEW_KEYWORDS is a non-empty array of strings", () => {
    assert.ok(Array.isArray(EXPLICIT_REVIEW_KEYWORDS) && EXPLICIT_REVIEW_KEYWORDS.length > 0);
  });

  it("TOOL_KEYWORDS covers the documented core keywords", () => {
    const required = ["bash", "curl", "api", "agent", "execute", "run"];
    for (const kw of required) {
      assert.ok(TOOL_KEYWORDS.includes(kw), `TOOL_KEYWORDS missing documented keyword "${kw}"`);
    }
  });

  it("ORCHESTRATION_KEYWORDS covers multi-agent patterns", () => {
    assert.ok(
      ORCHESTRATION_KEYWORDS.some((kw) => kw.includes("agent")),
      "ORCHESTRATION_KEYWORDS should include at least one 'agent' phrase",
    );
  });
});

// ---------------------------------------------------------------------------
// classifyPrompt — stable routing for representative inputs
// ---------------------------------------------------------------------------

describe("classifyPrompt routing stability", () => {
  it("routes an explicit review request to reasoning tier", () => {
    const r = classifyPrompt("please review this pull request for bugs");
    assert.equal(r.kind, "review");
    assert.equal(r.tier, "reasoning");
  });

  it("routes a lightweight question to economy tier", () => {
    const r = classifyPrompt("what is the capital of France");
    assert.equal(r.tier, "economy");
  });

  it("routes a simple implementation to builder tier", () => {
    const r = classifyPrompt("implement a login page");
    assert.equal(r.kind, "implementation");
    assert.equal(r.tier, "builder");
  });

  it("routes a planning request to builder or reasoning", () => {
    const r = classifyPrompt("design an architecture for the new API");
    assert.equal(r.kind, "planning");
    assert.ok(["builder", "reasoning"].includes(r.tier));
  });

  it("escalates a complex multi-file orchestration to reasoning", () => {
    const r = classifyPrompt(
      "implement a multi-agent system using parallel agents with tool chain across multiple files carefully",
    );
    assert.equal(r.tier, "reasoning");
  });

  it("returns a non-negative integer complexity score", () => {
    const r = classifyPrompt("explain this code");
    assert.ok(Number.isInteger(r.complexity) && r.complexity >= 0);
  });
});

// ---------------------------------------------------------------------------
// getTierCandidates ordering contracts
// ---------------------------------------------------------------------------

describe("getTierCandidates ordering", () => {
  it("review route starts with reasoning tier models", () => {
    const candidates = getTierCandidates({ kind: "review", tier: "reasoning" });
    const firstId = candidates[0].id;
    assert.ok(
      MODEL_CANDIDATES.reasoning.some((m) => m.id === firstId),
      `review route should start with a reasoning model, got ${firstId}`,
    );
  });

  it("economy lightweight route starts with economy tier models", () => {
    const candidates = getTierCandidates({ kind: "lightweight", tier: "economy" });
    const firstId = candidates[0].id;
    assert.ok(
      MODEL_CANDIDATES.economy.some((m) => m.id === firstId),
      `lightweight route should start with an economy model, got ${firstId}`,
    );
  });

  it("builder implementation route starts with builder tier models", () => {
    const candidates = getTierCandidates({ kind: "implementation", tier: "builder" });
    const firstId = candidates[0].id;
    assert.ok(
      MODEL_CANDIDATES.builder.some((m) => m.id === firstId),
      `builder implementation route should start with a builder model, got ${firstId}`,
    );
  });
});

// ---------------------------------------------------------------------------
// dedupeCandidates
// ---------------------------------------------------------------------------

describe("dedupeCandidates", () => {
  it("removes exact id+effort duplicates", () => {
    const input = [
      { id: "m", reasoningEffort: "high" },
      { id: "m", reasoningEffort: "high" },
      { id: "n", reasoningEffort: null },
    ];
    assert.equal(dedupeCandidates(input).length, 2);
  });

  it("keeps distinct effort levels as separate entries", () => {
    const input = [
      { id: "m", reasoningEffort: "medium" },
      { id: "m", reasoningEffort: "high" },
    ];
